output = {
    "tool_calls": [
        {"tool": "calculate", "parameters": {"expression": "2+2"}, "result": 4, "status": "success"},
        {"tool": "search_web", "parameters": {"query": None}, "error": "Missing query parameter", "status": "failed"},
        {"tool": "get_weather", "params": {"city": "NYC"}, "success": False, "error": "Timeout"}
