One acceptable solution (pseudocode):

```python
trajectory = []

def handle_event(evt):
    # 1) Normalize wrapper
    payload = None
    if isinstance(evt, dict) and 'data' in evt:          # RawResponsesStreamEvent
        payload = evt['data']
    elif isinstance(evt, dict) and 'item' in evt:        # RunItemStreamEvent
        payload = evt['item']
    else:
        payload = evt

    # 2) Ignore fine-grained/delta events
    delta_types = {
        'response.text.delta',
        'response.text.done',
        'response.content_part.done',
        'response.completed'
    }
    if isinstance(payload, dict) and payload.get('type') in delta_types:
        return

    # 3) Process completed output items
    if isinstance(payload, dict) and payload.get('type') == 'response.output_item.done':
        item = payload.get('item', {})
        item_type = item.get('type')

        if item_type == 'message':
            texts = []
            for part in item.get('content', []):
                if part.get('type') == 'output_text':
                    texts.append(part.get('text', ''))
            trajectory.append({
                'kind': 'message',
                'text': ''.join(texts)
            })

        elif item_type == 'function_call':
            trajectory.append({
                'kind': 'function_call',
                'name': item.get('name'),
                'arguments': item.get('arguments')
            })

        elif item_type == 'function_call_output':
            trajectory.append({
                'kind': 'function_call_output',
                'call_id': item.get('call_id'),
                'output': item.get('output')
            })
```

Key points: normalize wrapper (`data` vs `item`), skip delta/completion notifications, and only append normalized records when receiving `ResponseOutputItemDoneEvent` with item types `message`, `function_call`, or `function_call_output`.

