def parse_event(event):
    item = event.data.item
    if item.type == "message":
        # item.content is a list of parts; each part may have .type and .text
        texts = [part.text for part in item.content if part.type == "output_text"]
        return "".join(texts)
    elif item.type == "function_call":
        # arguments is a JSON-encoded string; return it as-is unless caller parses JSON
        return (item.name, item.arguments, item.call_id)
    elif item.type == "function_call_output":
        return (item.output, item.call_id)
    else:
        raise ValueError(f"Unknown item type: {item.type}")
```
